+SocketHandler::SocketHandler(PerformState& owner, curl_socket_t socket)
+  : folly::EventHandler{owner.evb_}, owner_{owner}, socket_{socket} {
+  initHandler(owner.evb_, folly::NetworkSocket::fromFd(socket));
+}
